```typescript
export type LeaseState =
  | { status: "empty" }
  | { status: "draft"; id: string; unitId: string; monthlyRent: number }
  | { status: "active"; id: string; unitId: string; monthlyRent: number; signedAt: string }
  | { status: "terminated"; id: string; terminatedAt: string };

export type LeaseCommand =
  | { type: "draft"; id: string; unitId: string; monthlyRent: number }
  | { type: "sign"; at: string }
  | { type: "terminate"; at: string };

export type LeaseEvent =
  | { type: "LeaseDrafted"; id: string; unitId: string; monthlyRent: number }
  | { type: "LeaseSigned"; at: string }
  | { type: "LeaseTerminated"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const leaseDecider: Decider<LeaseCommand, LeaseEvent, LeaseState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "draft": {
        if (state.status !== "empty") throw new DomainError("LEASE_EXISTS");
        if (command.monthlyRent <= 0) throw new DomainError("RENT_INVALID");
        return [{ type: "LeaseDrafted", id: command.id, unitId: command.unitId, monthlyRent: command.monthlyRent }];
      }
      case "sign": {
        if (state.status === "active") throw new DomainError("ALREADY_ACTIVE");
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "LeaseSigned", at: command.at }];
      }
      case "terminate": {
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "LeaseTerminated", at: command.at }];
      }
      default: {
        const _never: never = command;
        return _never;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LeaseDrafted":
        return { status: "draft", id: event.id, unitId: event.unitId, monthlyRent: event.monthlyRent };
      case "LeaseSigned":
        if (state.status !== "draft") return state;
        return { status: "active", id: state.id, unitId: state.unitId, monthlyRent: state.monthlyRent, signedAt: event.at };
      case "LeaseTerminated":
        if (state.status !== "active") return state;
        return { status: "terminated", id: state.id, terminatedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
