export type AgreementState =
  | { status: "none" }
  | { status: "draft"; id: string; lessee: string; term: number }
  | { status: "active"; id: string; lessee: string; term: number; start: string }
  | { status: "renewed"; id: string; lessee: string; term: number; renewedAt: string }
  | { status: "terminated"; id: string; endedAt: string };

export type AgreementCommand =
  | { type: "draft"; id: string; lessee: string; term: number }
  | { type: "activate"; start: string }
  | { type: "renew"; at: string }
  | { type: "terminate"; at: string };

export type AgreementEvent =
  | { type: "AgreementDrafted"; id: string; lessee: string; term: number }
  | { type: "AgreementActivated"; start: string }
  | { type: "AgreementRenewed"; at: string }
  | { type: "AgreementTerminated"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const agreementDecider: Decider<AgreementCommand, AgreementEvent, AgreementState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "draft":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.term <= 0) throw new DomainError("TERM_INVALID");
        return [{ type: "AgreementDrafted", id: command.id, lessee: command.lessee, term: command.term }];
      case "activate":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "AgreementActivated", start: command.start }];
      case "renew":
        if (state.status === "terminated") throw new DomainError("TERMINATED");
        if (state.status !== "active" && state.status !== "renewed") throw new DomainError("NOT_ACTIVE");
        return [{ type: "AgreementRenewed", at: command.at }];
      case "terminate":
        if (state.status === "terminated" || state.status === "none") throw new DomainError("INVALID_STATE");
        return [{ type: "AgreementTerminated", at: command.at }];
      default: {
        const _never: never = command;
        return _never;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AgreementDrafted":
        return { status: "draft", id: event.id, lessee: event.lessee, term: event.term };
      case "AgreementActivated":
        if (state.status !== "draft") return state;
        return { status: "active", id: state.id, lessee: state.lessee, term: state.term, start: event.start };
      case "AgreementRenewed":
        if (state.status !== "active" && state.status !== "renewed") return state;
        return { status: "renewed", id: state.id, lessee: state.lessee, term: state.term, renewedAt: event.at };
      case "AgreementTerminated":
        if (state.status === "none" || state.status === "terminated") return state;
        return { status: "terminated", id: state.id, endedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
