export type BlockEvent =
  | { type: "BlockRegistered"; blockId: string; name: string; totalUnits: number }
  | { type: "UnitOccupied"; blockId: string; unitId: string }
  | { type: "UnitVacated"; blockId: string; unitId: string }
  | { type: "MaintenanceLogged"; blockId: string; ticketId: string };

export interface BlockOccupancyView {
  readonly blockId: string;
  readonly name: string;
  readonly totalUnits: number;
  readonly occupiedUnits: number;
}

export const emptyView: BlockOccupancyView = {
  blockId: "",
  name: "",
  totalUnits: 0,
  occupiedUnits: 0,
};

export function project(view: BlockOccupancyView, event: BlockEvent): BlockOccupancyView {
  switch (event.type) {
    case "BlockRegistered":
      return { blockId: event.blockId, name: event.name, totalUnits: event.totalUnits, occupiedUnits: 0 };
    case "UnitOccupied":
      return { ...view, occupiedUnits: view.occupiedUnits + 1 };
    case "UnitVacated":
      return { ...view, occupiedUnits: Math.max(0, view.occupiedUnits - 1) };
    case "MaintenanceLogged":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function rebuildView(events: BlockEvent[]): BlockOccupancyView {
  return events.reduce(project, emptyView);
}
