interface StoredEvent<E> { data: E; revision: bigint }

interface AppendResult { nextRevision: bigint }

interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(
    stream: string,
    events: E[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<AppendResult>;
}

