      const state = stored.reduce<AmenityState>((a, e) => evolve(a, e.data), { status: "none" });
      const events = decide(cmd, state);
      const exp: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
      await write.appendToStream(s, events, { expectedRevision: exp });
