export function when(state: InspectionState, event: InspectionEvent): InspectionState {
  switch (event.type) {
    case "InspectionScheduled":
      return { ...state, id: event.id, status: "scheduled" };
    case "InspectionCompleted":
      return { ...state, status: "completed", score: event.score };
    case "InspectionCancelled":
      return { ...state, status: "cancelled" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function replay(events: InspectionEvent[]): InspectionState {
  return events.reduce(when, initialState);
}
